.gallery-page-root{
    width: 100%;
    padding: 0.8rem 0.8rem 1.2rem 0.8rem;
    box-sizing: border-box;
}

.gallery-top-bar{
    position: sticky;
    top: 0;
    z-index: 12;
    display: flex;
    justify-content: space-between;
    align-items: center;
    gap: 0.8rem;
    padding: 0.75rem 0.2rem 0.95rem 0.2rem;
    background: var(--bg-primary);
    border-bottom: 1px solid var(--border-card);
}

.gallery-title-shell{
    display: flex;
    flex-direction: column;
    gap: 0.15rem;
}

.gallery-title{
    margin: 0;
    font-family: "Lexend Deca", sans-serif;
    font-size: 1.2rem;
    color: var(--text-heading);
}

.gallery-subtitle{
    margin: 0;
    color: var(--text-faint);
    font-size: 0.76rem;
}

.gallery-sort-shell{
    display: inline-flex;
    align-items: center;
    gap: 0.35rem;
    background: var(--bg-secondary);
    border: 1px solid var(--border-card);
    border-radius: 999px;
    padding: 0.2rem;
}

.gallery-sort-btn{
    border: none;
    background: transparent;
    color: var(--text-faint);
    border-radius: 999px;
    padding: 0.35rem 0.7rem;
    font-size: 0.74rem;
    font-weight: 650;
    cursor: pointer;
}

.gallery-sort-btn.is-active{
    background: var(--bg-card);
    color: var(--text-heading);
}

.gallery-refresh-pill{
    margin: 0.8rem 0.2rem;
    font-size: 0.72rem;
    color: var(--text-faint);
}

.gallery-loading-state{
    width: 100%;
    min-height: 65vh;
    display: flex;
    justify-content: center;
    align-items: center;
}

.gallery-empty-state{
    width: 100%;
    min-height: 50vh;
    display: flex;
    justify-content: center;
    align-items: center;
    font-size: 0.86rem;
    color: var(--text-faint);
}

.gallery-masonry{
    column-count: 3;
    column-gap: 0.85rem;
    width: 100%;
    padding-top: 0.85rem;
    padding-bottom: 4rem;
}

.gallery-card{
    display: inline-block;
    width: 100%;
    margin: 0 0 0.85rem 0;
    border: 1px solid var(--border-card);
    border-radius: 12px;
    overflow: hidden;
    background: var(--bg-card);
    cursor: pointer;
    transition: transform 0.2s ease, box-shadow 0.2s ease;
}

.gallery-card:hover{
    transform: translateY(-2px);
    box-shadow: 0 8px 20px rgba(0, 0, 0, 0.08);
}

.gallery-preview-shell{
    position: relative;
    width: 100%;
    overflow: hidden;
    border-bottom: 1px solid var(--border-card);
    background: linear-gradient(150deg, #f9f2df 0%, #fef9ee 42%, #ebf4ff 100%);
}

.gallery-preview-shell.is-dark{
    background: linear-gradient(160deg, #1b1d23 0%, #21242f 50%, #262f42 100%);
}

.gallery-preview-image{
    position: absolute;
    inset: 0;
    width: 100%;
    height: 100%;
    object-fit: cover;
    opacity: 0.28;
}

.gallery-preview-snippets{
    position: absolute;
    inset: 0;
}

.gallery-preview-snippet{
    position: absolute;
    max-width: 52%;
    padding: 0.25rem 0.4rem;
    border-radius: 7px;
    font-size: 0.66rem;
    line-height: 1.32;
    color: #1c1d20;
    background: rgba(255, 255, 255, 0.74);
    border: 1px solid rgba(0, 0, 0, 0.05);
    word-break: break-word;
}

.gallery-preview-shell.is-dark .gallery-preview-snippet{
    background: rgba(8, 9, 12, 0.62);
    color: #f2f4ff;
    border-color: rgba(255, 255, 255, 0.08);
}

.gallery-preview-snippet.is-bold{
    font-weight: 700;
}

.gallery-card-body{
    display: flex;
    flex-direction: column;
    gap: 0.45rem;
    padding: 0.72rem 0.8rem 0.8rem;
}

.gallery-card-title{
    margin: 0;
    font-size: 0.93rem;
    line-height: 1.3;
    color: var(--text-heading);
}

.gallery-card-meta{
    display: flex;
    align-items: center;
    gap: 0.24rem;
    font-size: 0.69rem;
    color: var(--text-faint);
}

.gallery-author{
    font-weight: 600;
    color: var(--text-secondary);
}

.gallery-meta-dot{
    opacity: 0.7;
}

.gallery-card-score{
    display: inline-flex;
    align-items: center;
    justify-content: space-between;
    width: fit-content;
    min-width: 92px;
    border: 1px solid var(--border-card);
    border-radius: 999px;
    padding: 0.22rem 0.54rem;
    font-size: 0.64rem;
    color: var(--text-secondary);
    gap: 0.32rem;
}

@media (max-width: 900px){
    .gallery-masonry{
        column-count: 2;
    }
}

@media (max-width: 480px){
    .gallery-page-root{
        position: relative;
        top: 56px;
        padding: 0.6rem 0.4rem 1rem 0.4rem;
    }

    .gallery-top-bar{
        padding: 0.6rem 0.15rem 0.75rem 0.15rem;
    }

    .gallery-title{
        font-size: 1.05rem;
    }

    .gallery-subtitle{
        font-size: 0.69rem;
    }

    .gallery-sort-btn{
        font-size: 0.68rem;
        padding: 0.3rem 0.58rem;
    }

    .gallery-masonry{
        column-count: 1;
        column-gap: 0.6rem;
        padding-top: 0.6rem;
    }
}

