  33→const OPTIMISTIC_STAMP_PREFIX = "optimistic-stamp";
  34→const OPTIMISTIC_MARGIN_PREFIX = "optimistic-margin";
  35→const DOODLE_COLOR_PRESETS = [
  36→    "#5f92ff",
  37→    "#ff4d6d",
  38→    "#ff7f11",
  39→    "#ffd23f",
  40→    "#22c55e",
