 169→const CanvasImageNode = ({canvasImage, stageWidth, stageHeight, onStamp}) => {
 170→    const loadedImage = useLoadedImage(canvasImage?.src);
 171→    const objectWidth = clamp((canvasImage?.width || 0.3) * stageWidth, 56, stageWidth * 0.95);
 172→    const objectHeight = clamp((canvasImage?.height || 0.3) * stageHeight, 56, stageHeight * 0.95);
 173→    const x = clamp((canvasImage?.x || 0) * stageWidth, 0, Math.max(0, stageWidth - objectWidth));
 174→    const y = clamp((canvasImage?.y || 0) * stageHeight, 0, Math.max(0, stageHeight - objectHeight));
 175→
 176→    return (
 177→        <KonvaImage
 178→            x={x}
 179→            y={y}
 180→            width={objectWidth}
 181→            height={objectHeight}
 182→            image={loadedImage}
 183→            rotation={canvasImage?.rotation || 0}
 184→            scaleX={canvasImage?.scaleX === -1 ? -1 : 1}
 185→            onClick={onStamp}
 186→            onTap={onStamp}
 187→        />
 188→    );
 189→};
