 717→    }, [eventBelongsToJournal, journalId, marginsQueryKey, normalizeMarginRow, normalizeStampRow, queryClient, removeMarginFromCache, removeStampFromCache, stampsQueryKey, upsertMarginCache, upsertStampCache]);
 718→
 719→    useEffect(() => {
