/* ── Reset ── */
p {
    padding: 0;
    margin: 0;
}

/* ── Utility classes ── */
.text-truncate {
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}
.text-truncate-2 {
    display: -webkit-box;
    -webkit-line-clamp: 2;
    -webkit-box-orient: vertical;
    overflow: hidden;
    text-overflow: ellipsis;
}

/* ── Animations ── */
@keyframes skeleton-pulse {
    0% { opacity: 0.6; }
    50% { opacity: 0.3; }
    100% { opacity: 0.6; }
}
@keyframes dropdown-enter {
    from { opacity: 0; transform: translateY(-4px) scale(0.97); }
    to { opacity: 1; transform: translateY(0) scale(1); }
}
@keyframes toast-enter {
    from { opacity: 0; transform: translateY(12px); }
    to { opacity: 1; transform: translateY(0); }
}

/* ── Button system ── */
.btn-collection {
    display: inline-flex;
    justify-content: center;
    align-items: center;
    gap: 0.5rem;
    padding: 0.5rem 1rem;
    border-radius: 10px;
    font-family: inherit;
    font-size: 0.9rem;
    font-weight: 600;
    border: none;
    cursor: pointer;
    user-select: none;
    transition: background-color 0.15s ease, transform 0.1s ease, box-shadow 0.15s ease;
}
.btn-collection:active {
    transform: scale(0.97);
}
.btn-collection:focus-visible {
    outline: 2px solid var(--accent-purple);
    outline-offset: 2px;
}
.btn-collection:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}
.btn-collection:disabled:active {
    transform: none;
}
.btn-collection--primary {
    background-color: var(--accent-dark);
    color: var(--bg-primary);
}
.btn-collection--primary:hover:not(:disabled) {
    background-color: var(--accent-dark-hover);
}
.btn-collection--secondary {
    background-color: var(--bg-hover);
    color: var(--text-primary);
}
.btn-collection--secondary:hover:not(:disabled) {
    background-color: var(--border-light);
}
.btn-collection--danger {
    background-color: transparent;
    color: var(--color-danger);
}
.btn-collection--danger:hover:not(:disabled) {
    background-color: var(--color-danger-bg);
}

/* ── Character counter progress bar ── */
.char-counter-container {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    margin-top: 0.35rem;
}
.char-counter-bar {
    width: 60px;
    height: 4px;
    border-radius: 2px;
    background-color: var(--bg-hover);
    overflow: hidden;
}
.char-counter-fill {
    height: 100%;
    border-radius: 2px;
    transition: width 0.2s ease, background-color 0.2s ease;
}
.char-counter-fill--normal {
    background-color: var(--accent-sage);
}
.char-counter-fill--warning {
    background-color: var(--accent-amber);
}
.char-counter-fill--danger {
    background-color: var(--color-danger);
}
.char-counter-text {
    font-size: 0.75rem;
    color: var(--text-muted);
    font-variant-numeric: tabular-nums;
}

/* ── Privacy badge pills ── */
.privacy-badge {
    display: inline-flex;
    align-items: center;
    gap: 0.3rem;
    padding: 0.18rem 0.6rem;
    border-radius: 10px;
    font-size: 0.62rem;
    font-weight: 600;
    letter-spacing: 0.02em;
    user-select: none;
    border: 1px solid var(--border-card);
    background-color: var(--bg-pill);
}
.privacy-badge--public {
    color: var(--accent-sage);
}
.privacy-badge--private {
    color: var(--text-faint);
}

/* ── Selection checkmark ── */
.selection-check {
    position: absolute;
    top: 8px;
    right: 8px;
    width: 22px;
    height: 22px;
    border-radius: 50%;
    background-color: var(--accent-purple);
    display: flex;
    justify-content: center;
    align-items: center;
    z-index: 2;
}
.selection-check svg {
    width: 14px;
    height: 14px;
}

/* ── Skeleton card ── */
.skeleton-card {
    width: 31%;
    height: 220px;
    border-radius: 12px;
    background-color: var(--bg-hover);
    animation: skeleton-pulse 1.5s ease-in-out infinite;
}
.skeleton-card:nth-child(2) { animation-delay: 0.15s; }
.skeleton-card:nth-child(3) { animation-delay: 0.3s; }
.skeleton-card:nth-child(4) { animation-delay: 0.45s; }
.skeleton-card:nth-child(5) { animation-delay: 0.6s; }
.skeleton-card:nth-child(6) { animation-delay: 0.75s; }

/* ── Header (fixed) ── */
.collection-header {
    position: fixed;
    display: flex;
    justify-content: flex-start;
    align-items: center;
    gap: 1rem;
    padding: 1rem;
    width: 716px;
    height: 60px;
    user-select: none;
    background-color: var(--bg-glass);
    backdrop-filter: blur(25px);
    z-index: 125;
    border-bottom: 0.7px solid var(--border-light);
}
.collections-header-text {
    padding: 0;
    margin: 0;
    font-size: 1.2rem;
    font-weight: 600;
    color: var(--text-primary);
}

/* ── Intro banner ── */
.collection-intro-container {
    position: relative;
    top: 95px;
    display: flex;
    justify-content: flex-start;
    align-items: center;
    flex-direction: column;
    width: 95%;
    height: fit-content;
    padding: 1rem;
    background-color: var(--bg-primary);
    z-index: 119;
}
.collections-intro {
    text-align: center;
    display: flex;
    flex-direction: column;
    justify-content: center;
    align-items: center;
    width: 95%;
    padding: 1.5rem 1rem;
    height: 120px;
    background: linear-gradient(135deg, var(--accent-dark), var(--accent-dark-hover));
    color: var(--bg-primary);
    border-radius: 15px;
}
.collections-intro-h3 {
    display: flex;
    justify-content: center;
    align-items: center;
    font-size: 1.8rem;
    font-family: var(--font-serif);
    font-weight: 700;
    padding: 0;
    margin: 0;
}
.collections-intro-text {
    color: rgba(255, 255, 255, 0.8);
    font-size: 0.9rem;
}

/* ── Create button area ── */
.create-collection-container {
    position: relative;
    top: 97px;
    display: flex;
    width: 95%;
    padding: 1rem;
    justify-content: flex-end;
    align-items: center;
    color: var(--text-primary);
    z-index: 120;
}

/* ── Collection editor modal ── */
.collection-editor {
    position: absolute;
    top: 100px;
    transform: translateX(-50%);
    background-color: var(--bg-glass);
    backdrop-filter: blur(20px);
    border: 1px solid var(--bg-glass-border);
    box-shadow: var(--shadow-modal);
    width: 90%;
    max-height: 85vh;
    overflow-y: auto;
    z-index: 128;
    border-radius: 16px;
}
.is-saving-collections {
    width: 98%;
    padding: 0.5rem;
}
.collection-input-name {
    display: flex;
    flex-direction: column;
    padding: 1rem;
}
.input-name-container {
    display: flex;
    justify-content: flex-start;
    gap: 0.4rem;
    align-items: center;
    flex-wrap: wrap;
}
.field-name {
    font-weight: 700;
    color: var(--text-primary);
}
.input-name-collection {
    width: 80%;
    border: 1px solid var(--border-light);
    border-radius: 10px;
    font-size: 1.1rem;
    font-family: var(--font-ui);
    background-color: var(--bg-secondary);
    padding: 0.5rem 0.5rem;
    color: var(--text-primary);
    transition: border-color 0.15s ease, box-shadow 0.15s ease;
}
.input-name-collection:focus {
    outline: none;
    border-color: var(--accent-purple);
    box-shadow: 0 0 0 3px rgba(94, 66, 255, 0.1);
}
.collection-input-description {
    display: flex;
    flex-direction: column;
    padding: 1rem;
}
.input-description-container {
    display: flex;
    justify-content: flex-start;
    align-items: flex-start;
    gap: 0.4rem;
    flex-wrap: wrap;
}
.collection-description-limit {
    font-size: 0.8rem;
    padding: 0;
    margin: 0;
    color: var(--text-muted);
}
.collection-description {
    resize: none;
    padding: 0.5rem;
    background-color: var(--bg-secondary);
