/* ── Older posts modal ── */
.older-post-container {
    position: absolute;
    top: 40px;
    display: flex;
    flex-direction: column;
    align-items: flex-start;
    justify-content: flex-start;
    width: 90%;
    height: 80%;
    background-color: var(--bg-elevated);
    z-index: 129;
