}
.older-loading-container {
    position: absolute;
    top: 40px;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    width: 90%;
    height: 80%;
    background-color: var(--bg-elevated);
    z-index: 115;
    border-radius: 16px;
    padding: 1rem;
    box-shadow: var(--shadow-modal);
}
.old-post-cards {
    position: relative;
