    align-items: flex-start;
    flex-direction: column;
    width: 98%;
    height: fit-content;
    background-color: var(--bg-hover);
    padding: 0.5rem;
    border-radius: 10px;
    cursor: pointer;
    border: 2px solid transparent;
    transition: background-color 0.15s ease, border-color 0.15s ease;
}
.old-post-cards:hover {
    background-color: var(--bg-selection);
}
.inview-container {
    display: flex;
    width: 100%;
    height: 10px;
}
.old-post-cards-selected {
    position: relative;
    display: flex;
    align-items: flex-start;
    flex-direction: column;
    width: 98%;
    height: fit-content;
    background-color: var(--bg-selection);
    padding: 0.5rem;
    border-radius: 10px;
