}
.collection-journal-title {
    font-size: 1.2rem;
    font-weight: 700;
    color: var(--text-primary);
}
.collection-title-text-limit {
    margin: 0;
    padding: 0;
    font-size: 0.8rem;
    color: var(--text-muted);
}
.collection-sliced-text {
    font-size: 0.9rem;
    color: var(--text-secondary);
}
.cards-container {
    position: relative;
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
    overflow-y: auto;
    overflow-x: hidden;
}
.save-older-post-container {
    display: flex;
    justify-content: space-between;
    width: 100%;
    padding-top: 0.5rem;
}
.save-child-container {
    display: flex;
    justify-content: center;
    align-items: center;
    gap: 1rem;
}
.selected-post {
    padding: 0;
    margin: 0;
    font-weight: 660;
    color: var(--text-primary);
}

/* ── Journal entries ── */
.journal-title {
    display: flex;
    width: 100%;
    height: fit-content;
    font-size: 1.4rem;
    font-weight: 700;
    color: var(--text-primary);
}
.journal-text {
    display: flex;
    width: 100%;
    height: fit-content;
    font-size: 0.9rem;
    color: var(--text-secondary);
}

/* ── Collection cards container ── */
.collection-cards-container {
    position: relative;
    top: 115px;
    padding: 1rem;
    display: flex;
    justify-content: flex-start;
    align-items: flex-start;
    max-height: fit-content;
    min-height: 100%;
    width: 95%;
    background-color: var(--bg-primary);
    z-index: 119;
    gap: 0.8rem;
    flex-wrap: wrap;
}
.collection-cards-loading-container {
    position: relative;
    top: 115px;
    padding: 1rem;
    display: flex;
    justify-content: flex-start;
    align-items: flex-start;
    height: fit-content;
    width: 95%;
    background-color: var(--bg-primary);
    z-index: 120;
    gap: 0.8rem;
    flex-wrap: wrap;
}
.collection-cards-inview-container {
    display: flex;
    justify-content: center;
    align-items: center;
    width: 100%;
    height: 50px;
    z-index: 122;
}

/* ── Collection card (individual) ── */
.collection-cards {
    position: relative;
    display: flex;
    justify-content: flex-start;
    align-items: stretch;
    flex-direction: column;
    width: calc(50% - 0.5rem);
    height: 220px;
    background-color: var(--bg-card);
    border: 1px solid var(--border-card);
    border-radius: 12px;
    cursor: pointer;
    transition: transform 0.25s ease, box-shadow 0.25s ease;
    box-shadow: none;
    overflow: hidden;
}
.collection-cards:hover {
    transform: translateY(-2px);
    box-shadow: 0 6px 24px rgba(0, 0, 0, 0.07);
}

/* ── Gradient header with data-accent variants ── */
.collection-gradient-header {
    position: relative;
    display: flex;
    justify-content: center;
    align-items: center;
    border-radius: 14px 14px 0 0;
    width: 100%;
    height: 110px;
    overflow: hidden;
    border-bottom: 1px solid var(--border-card);
    transition: opacity 0.3s ease, filter 0.3s ease;
}
.collection-cards:hover .collection-gradient-header {
    opacity: 0.96;
    filter: brightness(1.05);
}
.collection-gradient-header[data-accent="0"] {
    background: linear-gradient(135deg, #6B8F71, #4a7a52);
}
.collection-gradient-header[data-accent="1"] {
    background: linear-gradient(135deg, #7c6aef, #5e42ff);
}
.collection-gradient-header[data-accent="2"] {
    background: linear-gradient(135deg, #e6a040, #d4880a);
}
.collection-gradient-header[data-accent="3"] {
    background: linear-gradient(135deg, var(--accent-dark), var(--accent-dark-hover));
}
.collection-gradient-header svg {
    opacity: 0.2;
}

/* ── CollectionViewer enhanced cards ── */
.cv-grid {
    display: grid;
    grid-template-columns: repeat(2, 1fr);
    gap: 0.75rem;
    width: 100%;
}
.cv-skeleton {
    height: 190px;
    border-radius: 14px;
    background-color: var(--bg-hover);
    animation: skeleton-pulse 1.5s ease-in-out infinite;
}
.cv-skeleton:nth-child(2) { animation-delay: 0.15s; }
.cv-skeleton:nth-child(3) { animation-delay: 0.3s; }
.cv-skeleton:nth-child(4) { animation-delay: 0.45s; }
.cv-card {
    position: relative;
    display: flex;
    flex-direction: column;
    background-color: var(--bg-card);
    border: 1px solid var(--border-card);
    border-radius: 14px;
    overflow: hidden;
    cursor: pointer;
    transition: transform 0.25s ease, box-shadow 0.25s ease, border-color 0.25s ease;
}
.cv-card:hover {
    transform: translateY(-3px);
    box-shadow: 0 8px 28px rgba(0, 0, 0, 0.08);
    border-color: var(--bg-glass-border);
}
.cv-gradient-header {
    position: relative;
    display: flex;
    justify-content: center;
    align-items: center;
    width: 100%;
    height: 80px;
    overflow: hidden;
    border-bottom: 1px solid var(--border-card);
    transition: filter 0.3s ease;
}
.cv-card:hover .cv-gradient-header {
    filter: brightness(1.06);
}
.cv-gradient-header[data-accent="0"] {
    background: linear-gradient(135deg, #6B8F71, #4a7a52);
}
.cv-gradient-header[data-accent="1"] {
    background: linear-gradient(135deg, #7c6aef, #5e42ff);
}
.cv-gradient-header[data-accent="2"] {
    background: linear-gradient(135deg, #e6a040, #d4880a);
}
.cv-gradient-header[data-accent="3"] {
    background: linear-gradient(135deg, var(--accent-dark), var(--accent-dark-hover));
}
.cv-gradient-header svg {
    color: #ffffff;
    opacity: 0.18;
}
.cv-badge {
    position: absolute;
    top: 8px;
    right: 8px;
    display: inline-flex;
    align-items: center;
    gap: 0.25rem;
    padding: 0.15rem 0.5rem;
    border-radius: 10px;
    font-size: 0.6rem;
    font-weight: 600;
    letter-spacing: 0.02em;
    user-select: none;
    backdrop-filter: blur(8px);
    -webkit-backdrop-filter: blur(8px);
}
.cv-badge svg {
    opacity: 1 !important;
}
.cv-badge--public {
    background: rgba(255, 255, 255, 0.18);
    border: 0.5px solid rgba(255, 255, 255, 0.25);
    color: rgba(255, 255, 255, 0.9);
}
.cv-badge--private {
    background: rgba(0, 0, 0, 0.2);
    border: 0.5px solid rgba(255, 255, 255, 0.12);
    color: rgba(255, 255, 255, 0.7);
}
.cv-card-body {
    display: flex;
    flex-direction: column;
    padding: 0.65rem 0.8rem 0.75rem;
    gap: 0.15rem;
}
.cv-card-name {
    font-family: "Lexend Deca", sans-serif;
    font-weight: 700;
    font-size: 0.92rem;
    line-height: 1.35;
    letter-spacing: -0.02rem;
    color: var(--text-heading);
}
.cv-card-date {
    font-family: var(--font-ui);
    font-size: 0.68rem;
    font-weight: 500;
    color: var(--text-faint);
}
.cv-card-description {
    margin-top: 0.2rem;
    font-family: var(--font-serif);
    font-size: 0.76rem;
    font-weight: 400;
    line-height: 1.45;
    color: var(--text-muted);
}

/* ── Legacy illustration (kept for CollectionViewer) ── */
.collection-illustration {
    position: relative;
    display: flex;
    justify-content: center;
    align-items: center;
    border-radius: 12px 12px 0 0;
    width: 100%;
    height: 180px;
    background: linear-gradient(135deg, var(--bg-hover), var(--bg-secondary));
}
.collection-illustration-img {
    width: 90%;
    height: 90%;
    object-fit: contain;
}

/* ── Settings button ── */
.setting-bttn {
    position: absolute;
    top: 0;
    right: 0;
    padding: 0.3rem;
    display: flex;
    width: 24px;
    height: 24px;
    border-radius: 6px;
    z-index: 130;
    user-select: none;
    cursor: pointer;
}
.setting-bttn:hover {
    background-color: var(--bg-hover);
}

/* ── Settings dropdown ── */
.collection-settings-container {
    position: absolute;
    background-color: var(--bg-elevated);
    display: flex;
    flex-direction: column;
    justify-content: flex-start;
    align-items: stretch;
    gap: 0;
    padding: 0.4rem;
    width: 160px;
    height: fit-content;
    top: 28px;
    right: 0;
    border-radius: 12px;
    box-shadow: var(--shadow-dropdown);
