    border-radius: 8px;
    font-size: 0.85rem;
    color: var(--text-primary);
}
.collection-settings-bttn:hover {
    background-color: var(--bg-hover);
}
.collection-settings-bttn--danger {
    color: var(--color-danger);
    border-top: 1px solid var(--border-light);
    margin-top: 0.2rem;
    padding-top: 0.55rem;
}
.collection-settings-bttn--danger:hover {
    background-color: var(--color-danger-bg);
}

/* ── Card name / date / description ── */
.collection-name-container {
    display: flex;
    width: 93%;
    padding: 0.7rem 0.9rem 0.25rem 0.9rem;
    justify-content: space-between;
    font-family: "Lexend Deca", sans-serif;
    font-weight: 700;
    font-size: 1.05rem;
    line-height: 1.35;
    letter-spacing: -0.02rem;
    color: var(--text-heading);
    transition: color 0.2s ease;
}
.collection-date-created {
    display: flex;
    justify-content: flex-start;
    align-items: center;
    gap: 0.5rem;
    font-family: var(--font-ui);
    font-size: 0.72rem;
    font-weight: 500;
    color: var(--text-faint);
    padding: 0.1rem 0.9rem;
