    display: flex;
    justify-content: flex-end;
    align-items: center;
    width: 95%;
    padding: 1rem;
    height: 60px;
}
.add-collection-button {
    display: flex;
    justify-content: center;
    align-items: center;
    padding: 0.5rem 0.8rem;
