}
.collections {
    display: flex;
    flex-direction: column;
    width: 31%;
    height: 320px;
    background-color: var(--bg-card);
    border: 1px solid var(--border-card);
    border-radius: 12px;
    box-shadow: none;
    cursor: pointer;
    transition: transform 0.25s ease, box-shadow 0.25s ease;
    overflow: hidden;
}
.collections:hover {
