    color: var(--text-primary);
}
.svg-close:hover {
    transform: scale(1.15);
}

/* ── Empty state ── */
.no-collections-container {
    display: flex;
    flex-direction: column;
    justify-content: center;
    align-items: center;
    width: 100%;
    min-height: 200px;
    z-index: 129;
    background-color: transparent;
    gap: 0.6rem;
    padding: 2.5rem 1.5rem;
