    border-radius: 14px;
}
.empty-state-icon-ring {
    display: flex;
    align-items: center;
    justify-content: center;
    width: 52px;
    height: 52px;
    border-radius: 50%;
    background-color: var(--bg-glass);
    border: 0.5px solid var(--bg-glass-border);
    color: var(--text-faint);
    margin-bottom: 0.25rem;
}
.empty-state-icon {
    width: 64px;
    height: 64px;
