}
.empty-state-title {
    font-family: "Lexend Deca", sans-serif;
    font-size: 1rem;
    font-weight: 600;
    color: var(--text-secondary);
    margin: 0;
    letter-spacing: -0.01em;
}
.empty-state-description {
    font-size: 0.8rem;
    color: var(--text-muted);
    max-width: 240px;
    line-height: 1.5;
    margin: 0;
}

/* ── Not collected journals modal ── */
.notCollectedJournalList {
    display: flex;
    flex-direction: column;
    position: absolute;
    background-color: var(--bg-elevated);
    box-shadow: var(--shadow-modal);
    border-radius: 16px;
    z-index: 130;
    width: 85%;
    height: 95%;
    padding: 1rem;
    top: 100px;
    gap: 0;
    overflow-y: auto;
    overflow-x: hidden;
}
.close-bttn-container {
    display: flex;
    justify-content: flex-end;
    align-items: center;
    width: 100%;
    height: fit-content;
}
.close-bttn {
    display: flex;
    justify-content: center;
    width: fit-content;
    height: fit-content;
    border-radius: 50%;
