    }
    .view-collection-header {
        width: 100%;
    }
    .cv-grid {
        grid-template-columns: 1fr;
    }
    .skeleton-card {
        width: 100%;
        height: 160px;
    }
    .collection-cards-selected-old-post {
        width: 45%;
    }
    .create-or-add-container {
        width: 90%;
        height: 40px;
        gap: 0.5rem;
        margin-top: 0.5rem;
    }
    .collection-journal-cards-container {
        display: flex;
        position: relative;
        top: 335px;
        width: 100%;
        min-height: 100vh;
        align-items: flex-start;
        justify-content: center;
    }
    .collection-journal-cards {
        width: 95%;
        height: auto;
    }
    .collection-name-container {
        font-size: 1rem;
    }
    .collections-title {
        font-size: 0.85rem;
    }
    .bookshelf {
