        margin-bottom: 4rem;
        height: fit-content;
        padding: 0.75rem;
    }
    .saving-loding-container {
        width: 93%;
    }
    .notCollectedJournalList {
        width: 90%;
        border-radius: 12px;
    }
    .older-post-container {
