        border-radius: 12px;
    }
    .collection-editor {
        position: absolute;
        top: 100px;
        transform: translateX(-50%);
        background-color: var(--bg-glass);
        backdrop-filter: blur(20px);
        border: 1px solid var(--bg-glass-border);
        box-shadow: var(--shadow-modal);
        width: 90%;
        max-height: 85vh;
        overflow-y: auto;
        z-index: 128;
        border-radius: 16px;
    }
}

