    }

    .gallery-page-root--embedded{
        width: 94%;
        top: 0;
        margin-top: 0.85rem;
        padding: 0.6rem;
        border-radius: 14px;
    }

    .gallery-top-bar{
        padding: 0.6rem 0.15rem 0.75rem 0.15rem;
    }

    .gallery-title{
        font-size: 1.05rem;
    }

    .gallery-subtitle{
        font-size: 0.69rem;
    }

    .gallery-sort-btn{
        font-size: 0.68rem;
        padding: 0.3rem 0.58rem;
    }

    .gallery-masonry{
        column-count: 1;
        column-gap: 0.6rem;
        padding-top: 0.6rem;
    }
}

